llm_verdict.message:
[
  {
    "function": "run_cmd",
    "parameters": {
      "command": "rpm -q usbguard >/dev/null 2>&1 || dnf install -y usbguard -y"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "mkdir -p /etc/usbguard"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "usbguard generate-policy > /etc/usbguard/rules.conf"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "if [ ! -s /etc/usbguard/rules.conf ]; then echo '# No USB devices detected' > /etc/usbguard/rules.conf; fi"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "chmod 0600 /etc/usbguard/rules.conf"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "chown root:root /etc/usbguard/rules.conf"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "systemctl daemon-reload"
    }
  },
  {
    "function": "run_cmd",
    "parameters": {
      "command": "systemctl enable --now usbguard.service"
    }
  }
]

